import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import { TrendingUp, TrendingDown } from '@mui/icons-material';
import response from './response.json';

interface MonthlyRevenue {
  month: string;
  revenue: number;
}

interface RevenueData {
  monthlyRecurringRevenue: number;
  churnRate: number;
  growthTrend: MonthlyRevenue[];
}

export default function Widget() {
  const data = response.data as RevenueData;
  const isGrowthPositive = data.growthTrend[data.growthTrend.length - 1].revenue >= data.growthTrend[0].revenue;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#303030' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 0.5 }}>
              Monthly Recurring Revenue
            </Typography>
            <Typography variant="h4" sx={{ color: '#FF5722', fontWeight: 600 }}>
              ${data.monthlyRecurringRevenue.toLocaleString()}
            </Typography>
            <Stack direction="row" alignItems="center" spacing={0.5} sx={{ mt: 0.5 }}>
              {isGrowthPositive ? <TrendingUp sx={{ fontSize: 16, color: '#10B981' }} /> : <TrendingDown sx={{ fontSize: 16, color: '#EF4444' }} />}
              <Typography variant="body2" sx={{ color: isGrowthPositive ? '#10B981' : '#EF4444' }}>
                {isGrowthPositive ? '+' : '-'}{data.churnRate.toFixed(2)}% Churn Rate
              </Typography>
            </Stack>
          </Box>

          <LineChart
            height={120}
            series={[
              {
                data: data.growthTrend.map(g => g.revenue),
                color: '#FFC107',
                curve: 'linear',
                showMark: false,
              },
            ]}
            xAxis={[{ data: data.growthTrend.map(g => g.month), hide: true }]}
            margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
            sx={{
              '& .MuiLineElement-root': {
                strokeWidth: 2,
              },
            }}
          />
        </Stack>
      </CardContent>
    </Card>
  );
}
